function ErrorAlert(n,t){alertify.alert().setHeader('<i class="fas fa-exclamation-triangle" style="color:#E62020"><\/i>오류').setting({label:"확인",message:n}).set({onok:function(){t&&t()}}).show()}function NormalAlert(n,t){alertify.alert().setHeader('<i class="fas fa-bell blue-600"><\/i>알림').setting({label:"확인",message:n}).set({onok:function(){t&&t()}}).show()}function ConfirmAlert(n,t,i,r){alertify.confirm().set({labels:{ok:"확인",cancel:"취소"},onok:function(){i&&i();confirmObj=!0},oncancel:function(){r&&r();confirmObj=!1;return}}).setHeader('<i class="fas fa-exclamation-triangle" style="color:#FFDC2E"><\/i>'+n).setting({message:t}).show()}function ConfirmAlert2(n,t){alertify.confirm().set({labels:{ok:"확인",cancel:"취소"},onok:function(){return!0},oncancel:function(){return!1}}).setHeader('<i class="fas fa-exclamation-triangle" style="color:#FFDC2E"><\/i>'+n).setting({message:t}).show()}